import { isUndefined } from 'lodash-es';
import { useCallback, useState } from 'react';

/**
 * Ref callback to be attached to an element. It'll run when the element is
 * loaded, so we can relly on it to ensure the DomNode is already cached.
 */
export const useSafeSvgParser = () => {
  const [elementAsString, setElementAsString] = useState('');
  const ref = useCallback((node: HTMLDivElement) => {
    if (node === null) {
      return;
    }

    /*
     * At this moment the parent might be loaded and should be something like
     * "<div><div ref={callback}><svg>icon</svg></div></div>" and we are step
     * in the node that has the reference attached.
     * Easy to read from now on.
     */
    const svgElement = node.getElementsByTagName('svg')[0];
    if (isUndefined(svgElement)) {
      return;
    }
    const stringSvg = new XMLSerializer().serializeToString(svgElement);
    const value = encodeURIComponent(stringSvg) ?? '';
    setElementAsString(value);
  }, []);
  return { elementAsString, ref };
};
